mcp__supabase__apply_migration 으로 다음 SQL 실행:
1. DO $$ BEGIN CREATE TYPE public.case_status AS ENUM ('draft','generating','completed','failed'); EXCEPTION WHEN duplicate_object THEN null; END $$;
2. 동일 패턴으로 bed_zone ('A','B','R') 생성
3. 동일 패턴으로 input_layout ('single','split_vertical','split_horizontal') 생성
4. ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS input_layout public.input_layout NOT NULL DEFAULT 'single';

'use client' 컴포넌트:
props: { caseId: string, initialStatus: string }

useEffect:
  if initialStatus === 'completed' || initialStatus === 'failed': return (폴링 불필요)

  const interval = setInterval(async () => {
    const res = await fetch(`/api/cases/${caseId}/status`)
    if (!res.ok) return
    const data = await res.json()
    if (data.status === 'completed' || data.status === 'failed') {
      clearInterval(interval)
      router.refresh()
    }
  }, 4000)

  return () => clearInterval(interval)

useRouter from 'next/navigation'
